#include<bits/stdc++.h>
using namespace std;
const int N=1000010;
int n,tot,in[31],top=0;
string str[N],ans[N];
vector<int> mp[31];
int son[N][31],cnt[N];
void insert(string s)
{
    int p=0,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        p=son[p][x];
    }
    cnt[p]++;
}
bool check(int id)
{
    for(int i=0;i<26;i++)
    {
        mp[i].clear();
    }
    memset(in,0,sizeof(in));
    int p=0,len=str[id].size();
    for(int i=0;i<len;i++)
    {
        int x=str[id][i]-'a';
        for(int j=0;j<26;j++)
        {
            if(son[p][j]&&j!=x)
            {
                mp[j].push_back(x);
                in[x]++;
            }
        }
        p=son[p][x];
        if(i!=len-1&&cnt[p]>0)
        {
            return false;
        }
    }
    queue<int> q;
    for(int i=0;i<26;i++)
    {
        if(in[i]==0)
        {
            q.push(i);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i:mp[t])
        {
            in[i]--;
            if(in[i]==0)
            {
                q.push(i);
            }
        }
    }
    for(int i=0;i<26;i++)
    {
        if(in[i]!=0)
        {
            return false;
        }
    }
    return true;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        cin>>str[i];
        insert(str[i]);
    }
    vector<int> ans;
    for(int i=1;i<=n;i++)
    {
        if(check(i))
        {
            ans.push_back(i);
        }
    }
    printf("%d\n",ans.size());
    for(int i:ans)
    {
        cout<<str[i]<<"\n";
    }
    return 0;
}
